import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'



class Room extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            screen: 0
        };
    }




        componentDidMount() {


            this.setState({screen: 1})

          }

          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []
              var rightContent = []
              var leftContent = []


              /*
              const options = [
                {value: '5930', label: 'Khanna, Raman'},
                {value: '1837', label: 'Sharpe, Bradley'},
                {value: '1850', label: 'Wu, Ethel'},
                {value: '3135', label: 'Shoeb, Marwa'},
                {value: '2470', label: 'Schaeffer, Sarah'},
                {value: '1889', label: 'Najafi, Nader'},
                {value: '6276', label: 'Lai, Andy'},
                {value: '6548', label: 'Auerbach, Andrew'}
              ]
*/

              const options = [
                {value: 'M-L Wards Team A', label: 'M-L Wards Team A'},
                {value: 'M-L Wards Team B', label: 'M-L Wards Team B'},
                {value: 'M-L Wards Team C', label: 'M-L Wards Team C'},
                {value: 'M-L Wards Team D', label: 'M-L Wards Team D'},
                {value: 'M-L Wards Team E', label: 'M-L Wards Team E'},
                {value: 'M-L Wards Team F', label: 'M-L Wards Team F'},
                {value: 'M-L Wards Team G', label: 'M-L Wards Team G'},
                {value: 'M-L Wards Team H', label: 'M-L Wards Team H'}
              ]


              const cardiologyOptions = [
                {value: '6709', label: 'Rounding Team, Cardiology A'},
                {value: '6710', label: 'Rounding Team, Cardiology B'}, 
                {value: '6711', label: 'Rounding Team, Cardiology C'}, 
                {value: '6712', label: 'Rounding Team, Cardiology D'}
              ]


              const goldmanOptions = [
                {value: 'gsm1', label: 'Rounding, Goldman Medicine #1'}, 
                {value: 'gsm2', label: 'Rounding, Goldman Medicine #2'},
                {value: 'gsm3', label: 'Rounding, Goldman Medicine #3'},
                {value: 'gsm4', label: 'Rounding, Goldman Medicine #4'},
                {value: 'gsm5', label: 'Rounding, Goldman Medicine #5'},
                {value: 'gsm6', label: 'Rounding, Goldman Medicine #6'},
                {value: 'gsm7', label: 'Rounding, Goldman Medicine #7'},
                {value: 'gsm8', label: 'Rounding, Goldman Medicine #8'},
                {value: 'gsm9', label: 'Rounding, Goldman Medicine #9'},
                {value: 'gsm10', label: 'Rounding, Goldman Medicine #10'}

              ]

              const timeOptions = [
                {value: '08:30', label: '08:30'},
                {value: '08:45', label: '08:45'}, 
                {value: '09:00', label: '09:00'}, 
                {value: '09:15', label: '09:15'},
                {value: '09:30', label: '09:30'},
                {value: '09:45', label: '09:45'},
                {value: '10:00', label: '10:00'},
                {value: '10:15', label: '10:15'},
                {value: '10:30', label: '10:30'},
                {value: '10:45', label: '10:45'},
                {value: '11:00', label: '11:00'},
                {value: '11:15', label: '11:15'},
                {value: '11:30', label: '11:30'},
                {value: '11:45', label: '11:45'},
                {value: '12:00', label: '12:00'}
              ]

              /*
              const groupedOptions = [
                {label: 'M-L Wards', options: options},
                {label: 'Rounding, Goldman Medicine', options: goldmanOptions}
              ]
              */
              const groupedOptions = [
                {label: 'M-L Wards', options: options}
              ]



              rightContent.push(<div style={{marginTop: "50px"}}>Send To:</div>)

              rightContent.push(<div style={{marginTop: "5px", display: "block"}}><Select
                  value={this.state.selectedSendTo}
                  isMulti
                  name="sendTo"
                  options={groupedOptions}
                  className="basic-multi-select"
                  classNamePrefix="select"
                  onChange={this.handleSendChange}
                /></div>)


              rightContent.push(<div style={{marginTop: "15px"}}>Message: <button onClick={() => this.handleMessage("Reminder MDR 10:30am. Please arrive within your scheduled time slot of 10:30am-10:30am. via 'Virtual' zoom.")} id="defaultMsg" style={{}}>MDR</button></div>)

              rightContent.push(<div style={{marginTop: "5px", display: "block"}}><textarea style={{width: "100%"}} id="message" name="message" rows="5"></textarea></div>)


              var buttonText = "Send Page"
              if (this.state.edit) {
                buttonText = "Edit Page"
              }

              rightContent.push(<div style={{textAlign: "right", marginTop: "15px"}}><button onClick={() => this.handleSendPage()}  id="sendPage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>{buttonText}</button></div>)


              leftContent.push(<div>Date To Send:</div>)

              /*
              leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar
              onSelect={(date) => {this.handleDateChange(date);}}
              selectDateType="multiple"
              slotInfo={false}
              showDateInputField={false}
              //onSelect={this.handleDateChange}
              /></div>)
              */
              leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar 
              //value={["10/01/2021","10/02/2021"]}
              //onChange={this.handleDateChange}
              value={this.state.selectedDate}
              onChange={dateArray => {this.handleDateChange(dateArray)}}
              multiple={true}
              format="MM/DD/YYYY"
              numberOfMonths={1}

            /></div>)
              leftContent.push(<div style={{marginTop: "15px"}}>Time To Send:</div>)
              leftContent.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="time" value={this.state.selectedTime} options={timeOptions} onChange={this.handleTimeChange}/></div>)


              content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px", width: "400px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div>)


              //this.state.savedPage

              if (this.state.savedPage.length > 0) {


                content.push(<div style={{marginTop: "50px"}}>Saved Pages<hr></hr></div>)



                for (let i in this.state.savedPage) {
                  var leftPageContent = []
                  var rightPageContent = []

                   var dates = ""
                   for (let j in this.state.savedPage[i].date_json) {
                     dates += this.state.savedPage[i].date_json[j].date + ", "
                   }
                   var sendTo = ""
                   for (let k in this.state.savedPage[i].send_to_json) {
                      sendTo += this.state.savedPage[i].send_to_json[k].label + "* "
                   }
                  var times = ""
                  for (let l in this.state.savedPage[i].time_json) {
                    times += this.state.savedPage[i].time_json[l].time + ", "
                  }




                  leftPageContent.push(<div>Date: {dates.substr(0, dates.length-2)}</div>)
                  leftPageContent.push(<div>Time: {times.substr(0, times.length-2)}</div>)
                  leftPageContent.push(<div>Send To: {sendTo.substr(0, sendTo.length-1)}</div>)
                  leftPageContent.push(<div>Message: {this.state.savedPage[i].message}</div>)

                  rightPageContent.push(<div><button onClick={() => this.handleEditPage(this.state.savedPage[i])}  id="editPage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "#CCCCCC" }}>Edit</button>&nbsp;<button onClick={() => this.handleDeletePage(this.state.savedPage[i])}  id="deletePage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "#CCCCCC" }}>Delete</button></div>)


                  content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px", flex: "70%"}}>{leftPageContent}</div><div style={{flex: "30%"}}>{rightPageContent}</div></div>)


                  content.push(<div><hr></hr></div>)

                }





              }

          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Room
